import React from "react";
import TaskCard from "./task-card";

const MyTask = ({ selectedTask }) => {
  if (!selectedTask)
    return <div className="empty-state">Select a task to see details</div>;

  return <div className="task-details-page"></div>;
};

export default MyTask;
